function getMaxSumAndCount(board) {
    const mod = 1000000007;
    const n = board.length;
    const dp = Array.from({ length: n }, () => Array.from({ length: n }, () => [0, 0]));
    dp[n - 1][n - 1] = [0, 1];

    for (let i = n - 1; i >= 0; i--) {
        for (let j = n - 1; j >= 0; j--) {
            if (board[i][j] === 'X' || (i === n - 1 && j === n - 1)) continue;
            const currVal = board[i][j] === 'E' ? 0 : parseInt(board[i][j]);
            const up = i > 0 ? dp[i - 1][j] : [-1, 0];
            const left = j > 0 ? dp[i][j - 1] : [-1, 0];
            const diag = i > 0 && j > 0 ? dp[i - 1][j - 1] : [-1, 0];

            const maxArray = getMax(up, left, diag);
            if (maxArray[0] === -1) continue;

            dp[i][j][0] = maxArray[0] + currVal;
            if (arraysEqual(up, maxArray)) dp[i][j][1] = (dp[i][j][1] + up[1] % mod) % mod;
            if (arraysEqual(left, maxArray)) dp[i][j][1] = (dp[i][j][1] + left[1] % mod) % mod;
            if (arraysEqual(diag, maxArray)) dp[i][j][1] = (dp[i][j][1] + diag[1] % mod) % mod;
        }
    }
    return dp[0][0];
}

function getMax(a, b, c) {
    if (a[0] >= b[0] && a[0] >= c[0]) return a;
    if (b[0] >= a[0] && b[0] >= c[0]) return b;
    return c;
}

function arraysEqual(a, b) {
    return a.length === b.length && a.every((val, index) => val === b[index]);
}
```


    The algorithm uses a `n x n` table called `dp` to store the maximum sum and the number of paths to achieve that sum for each cell on the board. It initializes the last cell (bottom right corner) with sum `0` and number of paths `1`.

Then, the algorithm iterates in reverse over the cells. If it encounters the starting cell or a cell marked with 'X', it skips that cell. Otherwise, it calculates the current value of the cell (either 0 in case of 'E' or the numeric character value), and checks for the maximum sum among up, left, and diagonal cells (ignoring the cells that are out of the board).

For the three cells (up, left, and diagonal) with the maximum sum, it adds their number of paths to the number of paths in the current cell modulo 1,000,000,007.

Finally, it returns the maximum sum and the number of paths for the first cell (top left corner) as the final result. In case there is no path, the returned value is [0, 0].

